from sympy import prime
import math
def sequence(n_max):
    results = []
    facts = [math.factorial(k) for k in range(0, 7)]
    for i in range(2, n_max + 1):
        gap = prime(i) - prime(i-1)
        if gap in facts:
            results.append(prime(i))
    return results
print(sequence(200))

